public class Main {

    public static void main(String[] args) throws Exception {
        int month = 1;
        double startAmount = 800000;
        double totalInterest = 0; // Переменная для хранения общей суммы процентов за 12 месяцев

        while (month <= 12) {
            double procentSumAmountMonth = startAmount * 0.125 / 12; // Расчет процентов для текущего месяца
